B.Fd=new A.d2("Advertising (Google AdSense)",null)
B.EM=new A.d1("This app uses Google AdSense to display advertisements. Third-party vendors, including Google, use cookies to serve ads based on prior visits to this site or other sites. You may opt out of personalised advertising by visiting google.com/settings/ads. For more information about how Google uses data when you use partner sites, see google.com/policies/technologies/partner-sites.",null)
