B.Jy=new A.b1(B.fz,["Hawa saaf. Bahar nikalne ka perfect din.","Zyaadatar logon ke liye theek. Sensitive logon ko halki dikkat.","Asthma/heart walon ko dikkat ho sakti hai. Baaki dhyaan se.","Saans mein dikkat ho sakti hai. Lambi outdoor activity avoid karo.","Sabko saans ki problem ho sakti hai. Bahar minimum rakho.","Emergency level. Healthy logon ko bhi serious asar. Bahar mat jaao."],t.li)
B.L9=new A.jv("\ud83d\udc55","T-shirt mein niklo!","Hawa saaf hai \u2014 bahar bhaago, enjoy karo!")
B.Lb=new A.jv("\ud83e\udde3","Scarf ya light mask \u2014 optional.","Bahar nikalna safe hai aaj. Hat bhi rakh lo.")
B.tg=new A.jv("\ud83d\ude37","Surgical mask pehno. Full sleeve better.","Bahar zyaada der mat ruko. Andar aao jaldi.")
B.La=new A.jv("\ud83e\udd7d","N95 + goggles. Poora dhakko.","Kam samay bahar raho. Lungs protest kar rahe hain.")
B.Ld=new A.jv("\ud83e\uddea","Hazmat mode on karo.","N95 + eye cover + gloves. Serious situation hai.")
B.Lc=new A.jv("\ud83d\ude80","Space suit chahiye bhai.","Yaar ghar pe raho. Koi bhi reason kaafi nahi.")
B.Jz=new A.b1(B.fz,[B.L9,B.Lb,B.tg,B.La,B.Ld,B.Lc],A.ak("b1<o,jv>"))
B.Hg=s(["Hawa actually saaf hai aaj! Screenshot le lo, ye roz nahi hota. Bahar bhaago!","AQI itna kam? Lag raha hai Delhi nahi, koi hill station hai.","Deep breath lene ka full paisa vasool din. Jeeyo, bahar jaao.","Aaj ki hawa certified fresh! Park mein jaao, dost ko call karo.","Yaar, aaj bahar nahi gaya toh pachtaoge. Seriously jaao."],t.s)
B.GE=s(["Theek-thaak hai. Mast nahi, par marne wala bhi nahi. Nikal jaao.","Aaj ki hawa: passing marks. Chal jayega.","Not great, not terrible. Dilli standard se toh bilkul theek hai.","Jaa sakte ho. Mask optional, attitude mandatory."],t.s)
B.HK=s(["Hawa 'thodi kharab' \u2014 matlab Delhi ke hisaab se normal. Mask rakh lo.","Mask optional hai, par ego pe mat lena. Pehen lo.","Thoda smog hai. Sunglasses aur mask dono kaam aayenge.","Bahar jao par zyaada gehri saans mat lo. Samjhe?"],t.s)
B.GD=s(["AQI 250+? Tumhare lungs ne resignation letter type kar diya. Ghar pe raho.","Bahar jaana hai? Pehle phephdo se permission le lo.","Aaj ki hawa free cigarette ke barabar. Smoker bano bina smoke kiye.","N95 pehno ya sofa pe baitho. Beech ka raasta nahi hai.","Ghar pe chai piyo. Hawa ne aaj aapko gift nahi diya."],t.s)
B.HI=s(["Khidki band karo. Bahar Delhi nahi, gas chamber hai. Maggi banao, andar raho.","AQI itna high ki air purifier ne bhi haath khade kar diye.","Bahar jaana = ek ghante mein 10 cigarette peena. Socho.","Aaj ke liye plan: Netflix, chai, aur khidki band."],t.s)
B.H8=s(["AQI 400 paar! Ye air nahi, soup hai. Bahar mat nikalna.","Mars pe rover bhej do, par Delhi ki hawa nahi sudhregi.","Emergency level. Seriously. Ghar mein raho. Ye maza nahi, warning hai.","Aaj bahar nikalna = direct pulmonologist appointment book karna."],t.s)
B.jm=new A.b1(B.fz,[B.Hg,B.GE,B.HK,B.GD,B.HI,B.H8],t.VJ)
B.H4=s(["\ud83c\udfc3 Subah ki jogging ke liye perfect time","\ud83e\ude9f Khidkiyaan kholo, taazi hawa aane do","\ud83c\udf3f Bachche bahar khel sakte hain bejhijhak","\u2615 Terrace pe chai ka maza lo aaj"],t.s)
B.Hi=s(["\ud83d\udeb6 Bahar jaana bilkul theek hai aaj","\ud83e\udd38 Exercise theek hai, zyada intense mat karo","\ud83d\ude37 Sensitive log chahein toh mask rakh sakte hain","\ud83e\ude9f Ventilation achhi hai, fresh air enjoy karo"],t.s)
B.HC=s(["\ud83d\ude37 Bahar jaate waqt mask pehno zaroor","\ud83c\udfc3 Heavy outdoor exercise avoid karo","\ud83c\udfe0 Asthma / heart patients ghar pe rahein","\ud83c\udf31 Ghar mein indoor plants lagao, thoda fark padta hai"],t.s)
B.H2=s(["\ud83c\udfe0 Ghar mein rehna behtar hai aaj","\ud83d\ude37 Bahar jaana ho toh N95 mask mandatory hai","\ud83d\udeab Outdoor exercise bilkul mat karo","\ud83d\udca8 Air purifier chalao ghar mein"],t.s)
B.HB=s(["\ud83d\udea8 Bahar jaana jitna ho sake avoid karo","\ud83d\udc74 Buzurg aur bachche ghar se bilkul mat niklein","\ud83e\ude9f Khidkiyaan band rakho, cracks seal karo","\ud83c\udfe5 Saans mein dikkat aaye toh turant doctor se milo"],t.s)
B.HQ=s(["\ud83c\udd98 Aaj ghar se mat niklo \u2014 emergency jaisi situation","\ud83e\ude9f Khidkiyaan aur darwaaze sealed band rakho","\ud83d\ude37 Nikalna absolutely zaroori ho toh N95 + eye cover","\ud83d\udcf5 Jogging, cycling, bahar kuch bhi \u2014 bilkul nahi aaj"],t.s)
B.JA=new A.b1(B.fz,[B.H4,B.Hi,B.HC,B.H2,B.HB,B.HQ],t.VJ)
